const raw = $json.body ?? $json;
const payload = (raw && typeof raw === 'object') ? (raw.data ?? raw) : {};
const headers = $json.headers || {};
const executionId = (typeof $execution !== 'undefined' && $execution?.id) ? String($execution.id) : String(Date.now());

const FIXED_CONFIG = {
  origin_name: 'Perpétuo Webinário',
  origin_id: 'bd1bd846-0c87-4acb-b221-d7f8d2089e68',
  tag_name: 'cj-ppt-webinar',
  lista_origem: 'cj-ppt-webinar',
  produto: 'VDE Carreiras Jurídicas Ciclo Prioritário',
  value: 2557,
  clint_base_url: 'https://api.clint.digital/v1'
};

function normalizeKey(value) {
  return String(value || '')
    .trim()
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[?!:;,.()\[\]'"%]/g, '')
    .replace(/[-_/]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeValue(value) {
  if (value === undefined || value === null) return '';

  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
    return String(value).trim();
  }

  if (Array.isArray(value)) {
    for (const item of value) {
      const extracted = normalizeValue(item);
      if (extracted) return extracted;
    }
    return '';
  }

  if (typeof value === 'object') {
    const priorityKeys = ['value', 'text', 'label', 'name', 'phone', 'email'];
    for (const key of priorityKeys) {
      if (Object.prototype.hasOwnProperty.call(value, key)) {
        const extracted = normalizeValue(value[key]);
        if (extracted) return extracted;
      }
    }
  }

  return '';
}

function digitsOnly(value) {
  return String(value || '').replace(/\D/g, '');
}

function cleanObject(obj) {
  return Object.fromEntries(
    Object.entries(obj || {}).filter(([, value]) => value !== undefined && value !== null && String(value).trim() !== '')
  );
}

function buildPhonePayload(rawPhone) {
  const phoneClean = digitsOnly(rawPhone);
  if (!phoneClean) return { ddi: '', phone: '', whatsapp_digits: '' };

  if (phoneClean.startsWith('55') && phoneClean.length > 11) {
    return {
      ddi: '+55',
      phone: phoneClean.slice(2),
      whatsapp_digits: phoneClean
    };
  }

  if (phoneClean.length === 10 || phoneClean.length === 11) {
    return {
      ddi: '+55',
      phone: phoneClean,
      whatsapp_digits: phoneClean
    };
  }

  return { ddi: '', phone: '', whatsapp_digits: phoneClean };
}

const containers = [
  payload,
  payload.fields || {},
  payload.custom_fields || {},
  payload.customFields || {},
  payload.contact || {},
  payload.subscriber || {},
  payload.variables || {}
].filter((item) => item && typeof item === 'object' && !Array.isArray(item));

function pickValue(aliases) {
  const normalizedAliases = aliases.map((alias) => normalizeKey(alias));

  for (const container of containers) {
    for (const [k, v] of Object.entries(container || {})) {
      const keyNorm = normalizeKey(k);
      if (normalizedAliases.includes(keyNorm)) {
        const cleaned = normalizeValue(v);
        if (cleaned) return cleaned;
      }
    }
  }

  return '';
}

const firstName = pickValue(['first_name', 'first name']);
const lastName = pickValue(['last_name', 'last name']);
const fullNameFallback = [firstName, lastName].filter(Boolean).join(' ').trim();

const nome = pickValue(['nome', 'name', 'full_name', 'full name', 'first_name']) || fullNameFallback;
const email = pickValue(['email', 'e-mail', 'mail', 'email_address', 'email address']).toLowerCase();

const whatsappRaw = pickValue([
  'whatsapp',
  'whatsapp_phone',
  'whatsapp phone',
  'phone',
  'telefone',
  'celular',
  'auth_phone',
  'auth phone'
]);

const carreiraPretendida = pickValue([
  'carreira_pretendida',
  'carreira pretendida',
  'carreira_concursos',
  'carreira concursos'
]);

const utmSource = pickValue(['utm_source', 'utm source', 'utmsource']);
const utmMedium = pickValue(['utm_medium', 'utm medium', 'utmmedium']);
const utmCampaign = pickValue(['utm_campaign', 'utm campaign', 'utmcampaign']);
const utmTerm = pickValue(['utm_term', 'utm term', 'utmterm']);
const utmContent = pickValue(['utm_content', 'utm content', 'utmcontent']);

const phonePayload = buildPhonePayload(whatsappRaw);
const hasContactIdentity = Boolean(email || phonePayload.phone);

const contactFields = cleanObject({
  carreira_pretendida: carreiraPretendida
});

const dealFields = cleanObject({
  utm_source: utmSource,
  utm_medium: utmMedium,
  utm_campaign: utmCampaign,
  utm_term: utmTerm,
  utm_content: utmContent,
  lista_origem: FIXED_CONFIG.lista_origem,
  data_importacao: new Date().toISOString(),
  produto: FIXED_CONFIG.produto
});

const tokenHeader = headers['x-clint-api-token'] || headers['X-CLINT-API-TOKEN'] || headers['api-token'] || headers['API-TOKEN'] || '';
const tokenPayload = normalizeValue(payload.clint_api_token || payload.clintToken || '');
const tokenEnv = (typeof process !== 'undefined' && process?.env)
  ? (process.env.CLINT_API_TOKEN || process.env.CLINT_TOKEN || process.env.API_TOKEN || '')
  : '';
const tokenFallback = 'U2FsdGVkX18umuKr+lSkwZrMxbDqBLAg7RXuFZdMCH6kgaNhWuW4RY9uSRh0OYTa+xfvC7xTs8oj+mYwdDTSiQ==';
const clintApiToken = normalizeValue(tokenHeader || tokenPayload || tokenEnv || tokenFallback);

if (!hasContactIdentity) {
  return [
    {
      json: {
        status: 'validation_error',
        code: 'VALIDATION_ERROR',
        message: 'Payload invalido: informe ao menos email ou whatsapp.',
        step: 'validate_payload',
        http_status: 400,
        execution_id: executionId,
        should_continue: false,
        fixed_config: FIXED_CONFIG,
        normalized_payload: {
          nome,
          email,
          whatsapp: whatsappRaw,
          whatsapp_digits: phonePayload.whatsapp_digits,
          ddi: phonePayload.ddi,
          phone: phonePayload.phone,
          carreira_pretendida: carreiraPretendida,
          utm_source: utmSource,
          utm_medium: utmMedium,
          utm_campaign: utmCampaign,
          utm_term: utmTerm,
          utm_content: utmContent
        },
        raw_payload: payload
      }
    }
  ];
}

return [
  {
    json: {
      status: 'validated',
      code: 'OK',
      message: 'Payload normalizado e validado.',
      step: 'normalize_input',
      http_status: 200,
      should_continue: true,
      execution_id: executionId,
      fixed_config: FIXED_CONFIG,
      integration_context: {
        clint_api_token: clintApiToken,
        clint_base_url: FIXED_CONFIG.clint_base_url
      },
      normalized_payload: {
        nome,
        email,
        whatsapp: whatsappRaw,
        whatsapp_digits: phonePayload.whatsapp_digits,
        ddi: phonePayload.ddi,
        phone: phonePayload.phone,
        carreira_pretendida: carreiraPretendida,
        utm_source: utmSource,
        utm_medium: utmMedium,
        utm_campaign: utmCampaign,
        utm_term: utmTerm,
        utm_content: utmContent
      },
      clint_payloads: {
        contactPayload: cleanObject({
          name: nome || (email ? email.split('@')[0] : `lead-${Date.now()}`),
          email,
          ddi: phonePayload.ddi,
          phone: phonePayload.phone,
          fields: contactFields
        }),
        dealPayloadBase: {
          value: FIXED_CONFIG.value,
          fields: dealFields
        }
      },
      raw_payload: payload
    }
  }
];

const input = $json;

if (!input.should_continue) {
  return [{ json: input }];
}

function extractId(payload) {
  return payload?.data?.id || payload?.id || null;
}

function cleanObject(obj) {
  return Object.fromEntries(
    Object.entries(obj || {}).filter(([, value]) => value !== undefined && value !== null && String(value).trim() !== '')
  );
}

function ensureFieldsObject(payload) {
  const fields = cleanObject(payload.fields || {});
  if (Object.keys(fields).length > 0) {
    payload.fields = fields;
  } else {
    delete payload.fields;
  }
  return payload;
}

const token = String(input.integration_context?.clint_api_token || '').trim();
const baseUrl = String(input.integration_context?.clint_base_url || 'https://api.clint.digital/v1').replace(/\/$/, '');
const executionId = input.execution_id || `${Date.now()}`;

if (!token) {
  return [{
    json: {
      status: 'integration_error',
      code: 'MISSING_CLINT_TOKEN',
      message: 'Token da Clint ausente. Envie x-clint-api-token no header (homologacao) ou configure credencial no n8n.',
      step: 'init_integration',
      http_status: 500,
      execution_id: executionId,
      normalized_payload: input.normalized_payload
    }
  }];
}

const httpRequest = this.helpers.httpRequest.bind(this.helpers);

async function apiRequest(step, method, path, body = undefined) {
  const url = `${baseUrl}${path}`;
  const maxAttempts = 3;

  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      const options = {
        method,
        url,
        headers: {
          'api-token': token,
          'Content-Type': 'application/json'
        },
        json: true,
        timeout: 20000
      };

      if (body !== undefined) {
        options.body = body;
      }

      return await httpRequest(options);
    } catch (error) {
      const statusCode = error?.statusCode || error?.response?.statusCode || null;
      const shouldRetry = attempt < maxAttempts && (statusCode === 429 || (statusCode >= 500 && statusCode < 600));

      if (shouldRetry) {
        await new Promise((resolve) => setTimeout(resolve, 300 * attempt));
        continue;
      }

      const details = error?.response?.body || error?.message || 'unexpected_error';
      const err = new Error(`Erro na Clint em ${step}: ${method} ${path}`);
      err.step = step;
      err.statusCode = statusCode || 500;
      err.details = details;
      throw err;
    }
  }
}

try {
  const originsResponse = await apiRequest('get_origins', 'GET', '/origins?limit=250');
  const origins = Array.isArray(originsResponse?.data) ? originsResponse.data : [];

  const wantedOriginId = input.fixed_config?.origin_id;
  const wantedOriginName = String(input.fixed_config?.origin_name || '').trim().toUpperCase();

  const origin = origins.find((item) => item?.id === wantedOriginId)
    || origins.find((item) => String(item?.name || '').trim().toUpperCase() === wantedOriginName);

  if (!origin?.id) {
    throw Object.assign(new Error('Origem alvo nao encontrada na Clint.'), {
      step: 'resolve_origin',
      statusCode: 502,
      details: { wanted_origin_id: wantedOriginId, wanted_origin_name: input.fixed_config?.origin_name }
    });
  }

  const stages = Array.isArray(origin?.stages) ? origin.stages : [];
  const baseStage = stages.find((stage) => String(stage?.type || '').toUpperCase() === 'BASE') || stages[0];

  if (!baseStage?.id) {
    throw Object.assign(new Error('Stage BASE nao encontrado para a origem informada.'), {
      step: 'resolve_stage',
      statusCode: 502,
      details: { origin_id: origin.id }
    });
  }

  const normalized = input.normalized_payload || {};
  const contactPayloadRaw = Object.assign({}, input.clint_payloads?.contactPayload || {});
  const contactPayload = ensureFieldsObject(cleanObject(contactPayloadRaw));

  let contactId = null;
  let contactOperation = '';

  if (normalized.email) {
    const emailSearch = await apiRequest('search_contact_email', 'GET', `/contacts?email=${encodeURIComponent(normalized.email)}`);
    const contactsByEmail = Array.isArray(emailSearch?.data) ? emailSearch.data : [];
    if (contactsByEmail[0]?.id) {
      contactId = contactsByEmail[0].id;
    }
  }

  if (!contactId && normalized.phone) {
    const phoneSearch = await apiRequest('search_contact_phone', 'GET', `/contacts?phone=${encodeURIComponent(normalized.phone)}`);
    const contactsByPhone = Array.isArray(phoneSearch?.data) ? phoneSearch.data : [];
    if (contactsByPhone[0]?.id) {
      contactId = contactsByPhone[0].id;
    }
  }

  if (contactId) {
    await apiRequest('update_contact', 'POST', `/contacts/${contactId}`, contactPayload);
    contactOperation = 'updated';
  } else {
    const created = await apiRequest('create_contact', 'POST', '/contacts', contactPayload);
    contactId = extractId(created);
    if (!contactId) {
      throw Object.assign(new Error('Falha ao extrair contact_id apos criar contato.'), {
        step: 'create_contact',
        statusCode: 502,
        details: created
      });
    }
    contactOperation = 'created';
  }

  const tagName = String(input.fixed_config?.tag_name || '').trim();
  if (tagName) {
    await apiRequest('add_tag', 'POST', `/contacts/${contactId}/tags`, [tagName]);
  }

  const dealPayloadBase = input.clint_payloads?.dealPayloadBase || {};
  const dealFields = cleanObject(dealPayloadBase.fields || {});
  const titleName = normalized.nome || normalized.email || normalized.phone || `lead-${executionId}`;

  const dealPayload = {
    contact_id: contactId,
    origin_id: origin.id,
    stage_id: baseStage.id,
    title: `${titleName} - ${input.fixed_config?.produto || 'Lead'}`,
    value: Number(input.fixed_config?.value || dealPayloadBase.value || 0),
    fields: dealFields
  };

  if (!Object.keys(dealFields).length) {
    delete dealPayload.fields;
  }

  const createdDeal = await apiRequest('create_deal', 'POST', '/deals', dealPayload);
  const dealId = extractId(createdDeal);

  return [{
    json: {
      status: 'success',
      code: 'OK',
      message: 'Lead processado com sucesso na Clint.',
      step: 'done',
      http_status: 200,
      execution_id: executionId,
      contact_id: contactId,
      contact_operation: contactOperation,
      deal_id: dealId,
      origin_id: origin.id,
      stage_id: baseStage.id,
      tag_name: tagName,
      normalized_payload: normalized
    }
  }];
} catch (error) {
  const httpStatus = Number(error?.statusCode || 502);
  return [{
    json: {
      status: 'integration_error',
      code: 'CLINT_INTEGRATION_ERROR',
      message: error?.message || 'Falha de integracao com a Clint.',
      step: error?.step || 'unknown_step',
      http_status: httpStatus >= 400 && httpStatus < 600 ? httpStatus : 502,
      execution_id: executionId,
      details: error?.details || null,
      normalized_payload: input.normalized_payload
    }
  }];
}

const status = String($json.status || '').trim().toLowerCase();

if (status && status !== 'success') {
  const code = String($json.code || 'WORKFLOW_ERROR');
  const message = String($json.message || 'Falha no workflow');
  throw new Error(`${code}: ${message}`);
}

return [{ json: $json }];
